// Script Continued Below
var DEBUG = false;
var debugUser = "kbaton";
// Assign script include for tasker common scripting methods
var tcs = new TaskerCommonScriptingMethods();
// var edm = new EmailDigestMethodsAndTemplates();
// define variables to be used throughout the script
// the following table names will be used by the tcs to query these tables
var userRoleTableName = "sys_user_has_role";
var taskTableName = "x_153465_discovert_route_task_instance";

// get the current Date and Time in UTC (system internal)
var getNow = function() {
	return new GlideDateTime().getValue();
};

// get the date/time one minute ago  in UTC (system internal)
var getOneMinuteAgo = function() {
	var minutesGlide = new GlideDateTime();
	minutesGlide.addSeconds(-60);
	return minutesGlide.getValue();
};

// get the beginning of this week
var getBeginningOfThisWeek = function() {
	return gs.beginningOfThisWeek();
};

// get the end of this week
var getEndOfThisWeek = function() {
	return gs.endOfThisWeek();
};

// get the date/time one week ago today in UTC (system internal)
var getOneWeekAgo = function() {
	var weekAgo = new GlideDateTime();
	weekAgo.addWeeksUTC(-1);
	return weekAgo.getValue();
};

// get the data/time one week into the future from today in UTC (system internal)
var getNextWeek = function() {
	var nextWeek = new GlideDateTime();
	nextWeek.addWeeksUTC(1);
	return nextWeek.getValue();
};

// get beginning of next week
var getBeginningOfNextWeek = function() {
	return gs.beginningOfWeek(getNextWeek());
};

// get end of next week
var getEndOfNextWeek = function() {
	return gs.endOfWeek(getNextWeek());
};

// create a basic search digest pattern, this captures all the reused code and conditions
// that are shared amongst all the queries that we need to perform, these conditions are
// repeated for the required digests, so it makes more sense to write once and re-use the function
var searchDigests = function(userId, andQuery) {
	var firstCount = 0;
	var secondCount = 0;
	//at this point, andQuery consists of date lookups for each user
	// what we want is to generally append additional static queries to return all user states
	// count the number of times we fired this object and return
	firstCount = tcs.countRelated(taskTableName, andQuery.concat([{"active":true},{"assigned_to":userId},{"state": ["IN","1,10,11,13,15"]}]));
		secondCount = tcs.countRelated(taskTableName, andQuery.concat([{"active":true},{"state":14}, {"u_reviewer": userId}]));
			return firstCount + secondCount;
		};

		// this is the final "Task overdue" query, which is slimmed down to just what makes it different
		// compared to the other three queries. Here you see that the only thing different is the suspense
		// date timing across all of the queries.
		var getOverdueVals = function(userId) {
			var now = getNow();
			var oneMinuteAgo = getOneMinuteAgo();
			var andQueries = [
			{"suspense_date":["<=", oneMinuteAgo]}
				];
				return searchDigests(userId, andQueries);
			};
			// search for all this weeks values when called
			var getThisWeekVals = function(userId) {
				var beginningOfWeek = getBeginningOfThisWeek();
				var endOfWeek = getEndOfThisWeek();
				var andQueries = [
				{"suspense_date":[">=", beginningOfWeek]},
					{"suspense_date":["<=", endOfWeek]}
						];
						return searchDigests(userId, andQueries);
					};
					// search for all next weeks values when called
					var getNextWeekVals = function(userId) {
						var beginningOfNextWeek = getBeginningOfNextWeek();
						var endOfNextWeek = getEndOfNextWeek();
						var andQueries = [
						{"suspense_date":[">=", beginningOfNextWeek]},
							{"suspense_date":["<=", endOfNextWeek]}
								];
								return searchDigests(userId, andQueries);
							};
							// search for all tasks that are upcoming when called
							var getUpcomingTaskVals = function(userId) {
								var endOfNextWeek = getEndOfNextWeek();
								var andQueries = [
								{"suspense_date":[">=", endOfNextWeek]}
									];
									return searchDigests(userId, andQueries);
								};

								//calls the previous functions to develop a stateful object containing our filtered results
								var getTaskDigestValues = function(userId) {
									var overdueVal = getOverdueVals(userId);
									var thisWeekVal = getThisWeekVals(userId);
									var nextWeekVal = getNextWeekVals(userId);
									var upcomingVal = getUpcomingTaskVals(userId);

									return {"Overdue":overdueVal, "ThisWeek":thisWeekVal, "NextWeek":nextWeekVal, "Upcoming":upcomingVal};
									};


									// Main execution block, this is the main methods that will call all of the above for each user
									if(DEBUG) {
										//DEBUG CODE
										try{
											var debugUserSysId = "";
											//get user sys id
											tcs.queryRelatedShort("sys_user", [{"user_name":debugUser}], function(user){
												debugUserSysId = user.sys_id;
												return null;
											}, true);

											if(debugUserSysId) {
												var templateValueMap = getTaskDigestValues(debugUserSysId);
												gs.eventQueue("x_153465_discovert.Email Digest Event",null,debugUserSysId,JSON.stringify(templateValueMap));
											} else {
												gs.warn("User not found.");
											}
										}catch(e) {
											gs.error(e);
										}
										//END DEBUG CODE
									} else {
										try{
											//get the sysId for the tasker_user role
											var roleTableName = "sys_user_role";
											var roleNametoIdQuery = [{"name":"x_153465_discovert.tasker_user"}];
												var roleRecords = tcs.queryRelated(roleTableName, roleNametoIdQuery, function(record){
													return record.sys_id;
												});
												//get all users with the tasker_user role and send digest
												var userQuery = [{"role":roleRecords[0]}];
													//create a tracker map that will quickly determine if a user has been notified already
													var trackUser = {};
														//actually create the digest for each user found
														tcs.queryRelated(userRoleTableName, userQuery, function(record) {
															if(!trackUser[record.user.sys_id]) {
																// generate the values that will go into the template
																var templateValueMap = getTaskDigestValues(record.user.sys_id);
																gs.eventQueue("x_153465_discovert.Email Digest Event",null,record.user.sys_id,JSON.stringify(templateValueMap));

																trackUser[record.user.sys_id] = true;
															}
															return null;
														});
													}catch(e) {
														gs.error(e);
													}
												}


												//For UNIT TESTING of single user
